// `render` runs per view (potentially multiple times for one model)
// and only handles DOM work: create a canvas, attach `nv` to it,
// seed Python with NiiVue defaults on first attach.
async function render({ model, el }) {
  const state = getState(model)
  await state.initializedPromise
  const nv = state?.nv
  if (!state || !nv) {
    console.error('ipyniivue: render called without an initialized NiiVue')
    return
  }
  const canvas = document.createElement("canvas")
  canvas.style.cssText = "width:100%;height:600px;display:block"
  canvas.width = 640
  canvas.height = 480
  el.appendChild(canvas)
  // One animation frame for layout to measure the parent.
  await new Promise((r) => requestAnimationFrame(() => r()))

  // Only the first render performs the attach + seed. Subsequent
  // views (e.g. same widget displayed in multiple cells) reuse
  // the existing nv on its existing canvas.
  if (!state.hasAttached) {
    await nv.attachToCanvas(canvas)
    state.hasAttached = true
    // Seed Python with NiiVue's actual current values.
    for (const [jsName, pyName] of [...PROPS_RW, ...PROPS_RO]) {
      try {
        const v = nv[jsName]
        if (v !== undefined) model.set(pyName, toJsonSafe(v))
      } catch (err) {
        console.warn("ipyniivue: failed to seed " + pyName + ":", err)
      }
    }
    if (state.mountedResolve) {
      state.mountedResolve()
      state.mountedResolve = null
    }
    try {
      model.save_changes()
    } catch (err) {
      console.warn('ipyniivue: failed to sync initial state:', err)
    }
  }
  return () => {
    // Per-view cleanup: nothing; canvas is detached by JupyterLab,
    // and `nv` is destroyed by the initialize-cleanup callback.
  }
}

